; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading) events.push2(3, 4);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="The Water Palace is a sanctuary for those who dwell in the water."

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@se f=kacha
@wait time=800
@se f=fence
@switchfence x=6 y=16 way=n mode=open
@wait time=1000
@notice text="I heard a door open somewhere!"
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true
*event_4
;[exp] true

; 必ず１つは水着が出る場所を設けることで永久に出ないのを防ぐ
@monster pos=1 name=マーメイド
@monster pos=2 name=マーメイド
@monster pos=3 name=マーメイド
@monster pos=4 name=マーメイド
@monster pos=5 name=マーメイド
@callbattle gameover=true
@delevent
@eval exp='game.inEvent = false'
@eval exp='tf.temp = game.dropTables[12].draw()'
@eval exp='game.treasureBox.drops.add(%[itemData: tf.temp, state: -WHOLE])'
@eval exp='game.appearTreasureBox()'
@saveon
[s]

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

; ハイパーボム専用宝箱
@treasure item=人魚のブラ,人魚のブラ,人魚のパンツ,人魚のパンツ,マーマンズシェル,貝のネックレス,貝のネックレス,経験のコイン（中）,経験のコイン（中）,経験のコイン（中）,経験のコイン（中）,経験のコイン（中） trap=罠はない
[if exp='! tf.leaveTreasureBox']
	@delevent
	@changefloor pimg=void click=false
[endif]

[eventoff]
